('2abd717b-e3c7-474f-8ee0-caa29eed1bb2', 'Vibe Coder', 'AI Chatbot Integration', '6000', 'session', 'Solo AI dev who integrates a working chatbot into your website or WhatsApp in one session. Comes to your office or works remotely. Powered by ChatGPT API, Dialogflow or custom logic. Handles FAQs, lead capture, booking queries and product questions automatically. Trained on your business data. Live and tested by end of session. Full handover in 24 hrs.', 6, true, '5.0', 112, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30004', 'ai.deepak@focsera.com', 'Deepak AI & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:30:26.695346+00', null, 15, true), 
('ca1c3a85-7748-4cf5-a671-cdfd90d89bd0', 'Photographer', 'Anniversary Shoot', '3500', 'session', 'Solo photographer arriving at your home with candles, fairy lights and a small prop bag. iPhone for ambient mood shots, mirrorless for portraits. Sets up a warm candlelit scene in 10 minutes. Edits on-site. 50 digital photos in 24 hrs. Framed anniversary portrait in 48 hrs.', 7, true, '5.0', 134, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11214', 'lalitha.anniv@focsera.com', 'Lalitha Menon & Team', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.46, 78.36, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('a506da20-0539-4732-9ecf-612633cfe7a8', 'Vibe Coder', 'App UI Revamp', '5500', 'session', '2-person app UI team — developer and designer. Comes to your office or works remotely. Revamps existing Flutter or React Native app screens — new colour scheme, typography, component styling and layout improvements. Up to 8 screens per session. No backend changes, pure UI. Live build pushed to your device by end of session. Full code handed over in 24 hrs.', 7, true, '5.0', 143, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30010', 'uirevamp.rahul@focsera.com', 'Rahul Dev & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.44, 78.3489, false, '2026-03-21 17:30:26.695346+00', null, 15, true), 
('a1ee1dd8-0f31-43a6-b8b2-dafea55addee', 'Developer', 'Automation & Scripts', '4500', 'session', 'Solo automation engineer who builds scripts and workflows that save your business hours every week. Works doorstep or remotely. Python, Node.js and Google Apps Script. Session 1: understand your manual process and design the automation. Session 2: build, test and deploy. Covers: spreadsheet automation, email workflows, WhatsApp bulk messaging, report generation, data scraping and API-to-API integrations. Most automations complete in 1–2 sessions.', 7, true, '5.0', 112, ARRAY[]::text[], '2026-03-21 17:41:16.254993+00', null, '+91 98400 50004', 'auto.vikram@focsera.com', 'Vikram Dev & Team', 'https://pub-962ecf16eb9a4629a9bf8d004682ebc5.r2.dev/AutomationsandScripts.png', 17.43, 78.38, false, '2026-03-21 17:41:16.254993+00', null, 15, true), 
('58dc305a-be52-4a4d-acce-350c45f18b7e', 'Photographer', 'Automobile / Bike Shoot', '4000', 'session', '2-person automobile team arriving at your home, garage or parking lot. iPhone for dynamic motion shots and detail reels, mirrorless with wide and telephoto lens for hero frames. Covers exterior angles, interior details, wheel close-ups and lifestyle shots with owner. 60 edited photos + 1 reel in 24 hrs. Framed poster in 48 hrs.', 6, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 12006', 'rohan.auto@focsera.com', 'Rohan Pillai & Team', 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?q=80&w=200&h=200&auto=format&fit=crop', 17.395, 78.48, false, '2026-03-21 17:18:30.121689+00', null, 20, true), 
('3406f065-31dd-4fb1-a168-68a58b2cb01f', 'Videographer', 'Automobile / Bike Video', '4500', 'session', '2-person auto video team. iPhone Pro on gimbal for cinematic panning and interior walkarounds, mirrorless with telephoto for hero exterior shots. Magnetic phone mount for driver POV. Comes to your home, parking lot or garage. Shoots and edits a 60-second cinematic car or bike reel on-site. Delivered in 24 hrs. Instagram, YouTube Shorts and WhatsApp Status ready.', 6, true, '4.9', 98, ARRAY[]::text[], '2026-03-21 17:24:58.380908+00', null, '+91 98400 20010', 'rohan.autovid@focsera.com', 'Rohan Pillai & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.395, 78.48, false, '2026-03-21 17:24:58.380908+00', null, 20, true), 
('412ac5a2-2450-47a7-9751-2b441d57f69c', 'Event Host', 'Award Night / Gala Host', '12000', 'session', 'Premium award night and gala host with a polished, formal stage presence. Hosts corporate award ceremonies, annual day functions and gala dinners. Prepares winner announcements, citation readings and entertaining interludes. Brings own wireless mic and confidence to any room size. Fluent in English with Telugu and Hindi as needed. Up to 4 hours. Hyderabad five-star hotels and convention centres familiar. Book 7 days in advance.', 10, true, '5.0', 134, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 90005', 'gala.meera@focsera.com', 'Meera Krishnan', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.45, 78.49, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('a152b254-6dae-4463-87e4-d7974deddf7b', 'Videographer', 'Baby Milestone Video', '4000', 'session', '2-person baby video team — videographer and baby-care assistant. Soft LED panel, iPhone for BTS moments and mirrorless for hero shots. Covers first steps, first words, tummy time and cake smash in a short film format. Edits a 3-minute emotional milestone video on-site. Delivered in 24 hrs with soft music and text cards. 1 month to 2 years covered.', 5, true, '5.0', 143, ARRAY[]::text[], '2026-03-21 17:24:58.380908+00', null, '+91 98400 20003', 'kavitha.baby@focsera.com', 'Kavitha Menon & Team', 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:24:58.380908+00', null, 15, true), 
('76e1362c-b38a-47b3-baf4-4d3fc88feb70', 'Event Planner', 'Baby Shower / Godh Bharai Planning', '5500', 'session', '2-person baby shower team specialising in Telugu Godh Bharai and modern baby shower formats. Arrives at your home or hall with full pastel floral setup — balloon arch, pampas grass backdrop, flower arrangements and game cards. Basic package: planning + vendor coordination. Full package: full setup + ceremony coordination + games hosting + pack-down. Catering vendor list and decoration guide provided.', 6, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:45:14.893664+00', null, '+91 98400 60004', 'shruti.babyshower@focsera.com', 'Shruti Kapoor & Team', 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?q=80&w=200&h=200&auto=format&fit=crop', 17.42, 78.45, false, '2026-03-21 17:45:14.893664+00', null, 15, true), 
('91f0498a-18be-487d-bd2c-065d97d3d9ec', 'Interior Designer', 'Bedroom / Living Room Makeover', '8000', 'session', 'Interior design team of 2 who execute a complete bedroom or living room makeover at your home. Session 1: measurement, mood board and shopping list. Session 2+: execution — furniture arrangement, décor placement, curtains, cushions, wall art and accessories. Sources from Hyderabad markets and online within your budget. Works with both rented and owned homes. Transformation visible from day one.', 7, true, '5.0', 156, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80002', 'room.divya@focsera.com', 'Divya Interiors & Team', 'https://images.unsplash.com/photo-1517841905240-472988babdf9?q=80&w=200&h=200&auto=format&fit=crop', 17.4486, 78.3908, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('cd722dea-4123-4099-83b2-f6c873061f43', 'Videographer', 'Birthday / Event Film', '4500', 'session', '2-person event film team. iPhone for wide candid coverage, mirrorless for cinematic highlight moments. Portable LED panel and lav mic in one bag. Covers décor, entry, cake cutting and dance floor energy. Edits a 2–3 minute highlight film on-site. Delivered in 24 hrs with background music and titles. Perfect for birthdays, house parties and small celebrations.', 5, true, '4.9', 167, ARRAY[]::text[], '2026-03-21 17:24:58.380908+00', null, '+91 98400 20002', 'karthik.events@focsera.com', 'Karthik Shetty & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.425, 78.465, false, '2026-03-21 17:24:58.380908+00', null, 15, true), 
('4ec4ee87-5d3f-4d12-ad50-2d1c0a0aaedb', 'Photographer', 'Birthday Party', '4500', 'session', '2-person birthday team covering your full party at home or a hall. iPhone for candid moments + mirrorless for group shots. Portable ring light in the bag. Edits while the party is still going. 70 digital photos in 24 hrs. Framed party collage in 48 hrs. Kids and adult birthdays both covered.', 7, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11206', 'karthik.bday@focsera.com', 'Karthik Shetty & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.425, 78.465, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('83aa475d-1cd7-4943-93c9-fd9840059fb3', 'Event Host', 'Birthday Party Host', '5000', 'session', 'High-energy birthday party host who comes to your home or party hall and runs the complete show. Covers welcome, games, dance rounds, quiz, cake ceremony and send-off. Brings portable Bluetooth speaker and game props kit. Kids and adult birthdays both handled. Bilingual — Telugu and English. Keeps the energy up for 2–3 hours. Books 3 days in advance. Available across Hyderabad.', 5, true, '4.9', 167, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 90001', 'host.karthik@focsera.com', 'Karthik Shetty', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.425, 78.465, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('b32941d3-bb67-4c98-9f9e-807de09f8ffa', 'Event Planner', 'Birthday Party Planning', '5000', 'session', '2-person birthday planning team who come to your home or hall and handle everything — balloon arch, backdrop, cake coordination, party games and return gifts. Basic package: planning + vendor coordination only. Full package: arrives 2 hours early, sets up complete décor, manages the event and packs down after. Kids and adult birthdays both covered. Hyderabad-wide. Book 3–5 days in advance.', 5, true, '4.9', 187, ARRAY[]::text[], '2026-03-21 17:45:14.893664+00', null, '+91 98400 60001', 'ananya.bday@focsera.com', 'Ananya Iyer & Team', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:45:14.893664+00', null, 20, true), 
('5fea4881-d0bd-46ba-8c60-d7fa6c8981ae', 'Photographer', 'Brand Story Shoot', '5500', 'session', '3-person brand story team — photographer, videographer and creative director. Arrives at your office, shop or home. Covers your founder story, team culture, product and workspace in one session. iPhone for candid storytelling, mirrorless for brand portraits. 80 edited photos + 1 brand reel in 24 hrs. Website, pitch deck and social media ready.', 9, true, '5.0', 167, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 12005', 'aryan.brand@focsera.com', 'Aryan Mehta & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.399, 78.477, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('a100900e-df03-47cd-b966-cffe92ba126c', 'Videographer', 'Brand Story Video', '5500', 'session', '3-person brand video team — director, videographer and editor. 2 mirrorless cameras, 1 LED panel, lav mic and iPhone for candid coverage. Comes to your office, shop or home. Covers founder story, team culture, product and workspace. Edits a 90-second brand film on-site. Delivered in 24 hrs. Website, pitch deck, Instagram and YouTube ready. Works for any business.', 9, true, '5.0', 156, ARRAY[]::text[], '2026-03-21 17:24:58.380908+00', null, '+91 98400 20009', 'aryan.brandvid@focsera.com', 'Aryan Mehta & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.399, 78.477, false, '2026-03-21 17:24:58.380908+00', null, 15, true), 
('c701baf4-bb95-48ab-97da-f7bb76dd362b', 'Vibe Coder', 'Bug Fixing / Code Review', '3500', 'session', 'Senior developer who dives into your codebase and fixes bugs in a single focused session. Doorstep or remote screen share. Flutter, React, Node.js, Python, PHP covered. Identifies root cause, fixes the issue, explains what went wrong and documents the fix. Up to 5 bugs per session. Code review and refactor suggestions included. Summary report delivered in 24 hrs.', 9, true, '5.0', 189, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30006', 'debug.vikram@focsera.com', 'Vikram Dev & Team', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:30:26.695346+00', null, 15, true), 
('1be3de90-de64-444a-84f1-3deb6159e887', 'Photographer', 'Business', '4500', 'session', '2-person interiors team arriving at your business with a wide-angle lens, portable LED panel and iPhone. Covers every corner — entrance, seating, product displays, team in action and detail shots. No heavy equipment, no disruption to customers. 70 edited interior photos in 24 hrs. Website, Google Business and social media ready.', 7, true, '4.8', 145, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 12004', 'meera.interiors@focsera.com', 'Meera Krishnan & Team', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.45, 78.49, false, '2026-03-21 17:18:30.121689+00', null, 20, true), 
('b615cae9-62ba-488a-955a-dcb527ed5931', 'Reel Maker', 'Business Promo Reel', '4500', 'session', '2-person business reel team arriving at your office, shop or coworking space. LED panel, lav mic and iPhone + mirrorless setup. Covers team in action, product, workspace and a short founder statement. Edits a polished 60–90 second business promo reel on-site. Trending music, text animations and logo added. Delivered in 24 hrs. Works for any business — IT, retail, food, services.', 7, true, '4.9', 156, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40006', 'aryan.bizreel@focsera.com', 'Aryan Mehta & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.399, 78.477, false, '2026-03-21 17:37:40.713931+00', null, 15, true), 
('d63ff3d0-de8b-4fdd-9eb0-51f7405e4341', 'Photographer', 'Cake Smash / First Birthday', '4500', 'session', '2-person first birthday team. Arrives with a backpack-sized kit: balloon pack, mini backdrop, LED ring light and iPhone + mirrorless. Sets up in 15 minutes at your home. Shoots the full smash, edits on-site. 60 digital photos in 24 hrs. Mini framed album in 48 hrs. Siblings and parents included.', 6, true, '5.0', 167, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11203', 'rohit.firstbday@focsera.com', 'Rohit Varma & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.415, 78.435, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('88c95bb9-242a-44d0-88bf-6ec63a3ee6a5', 'Photographer', 'Cinematic/Themed Shoot', '5500', 'session', '3-person cinematic team — photographer, videographer and editor. LED panel, colour gels and lens kit packed in two bags. iPhone on gimbal for cinematic movement, mirrorless for stills. Editor works on-site while the shoot continues. 60 graded photos + 1 short film in 24 hrs. Framed film-still print in 48 hrs.', 9, true, '5.0', 212, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11219', 'deepak.cinema@focsera.com', 'Deepak Rao & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('3332d75d-0710-4e98-bb95-029e381ce7b6', 'Interior Designer', 'Colour Consultation', '2500', 'session', 'Colour specialist who visits your home and recommends the perfect paint palette for every room. Brings physical paint swatches and colour chips. Tests colours against your lighting, flooring and furniture. Prepares a room-wise colour plan with exact paint codes (Asian Paints / Berger / Dulux). Accent wall and ceiling colour suggestions included. Full report delivered same day. Painter vendor list provided.', 5, true, '4.9', 223, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80004', 'colour.meera@focsera.com', 'Meera Interiors & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.45, 78.49, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('b14e8364-9124-45c0-b4ba-8658ab0a8da0', 'Editor', 'Colour Grading', '4000', 'session', 'Colour grading specialist who receives your footage and returns a cinematic colour grade remotely. DaVinci Resolve professional. Cinematic looks — teal and orange, film emulation, soft pastel, dark moody or clean natural. Up to 20 minutes of footage per session. LUT file provided after grading so you can apply the look to future footage yourself. Delivered in 24 hrs.', 7, true, '5.0', 143, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70011', 'color.aryan@focsera.com', ' आर्यन Edit & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.399, 78.477, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('f6f98f5f-66bb-478c-a4de-8c6bf1e24769', 'Event Host', 'Corporate Event Emcee', '8000', 'session', 'Professional corporate emcee with experience hosting IT conferences, team outings, award functions and product demos in Hyderabad. Fluent in Telugu, Hindi and English. Prepares a customised run-of-show with your event brief. Manages stage, audience, speakers and timing seamlessly. Brings own lapel mic and backup audio. Up to 4 hours. Trusted by Hyderabad IT parks and MNCs. Book 5 days in advance.', 8, true, '5.0', 143, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 90003', 'emcee.vikram@focsera.com', 'Vikram Joshi', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('161f5600-c0c0-4b48-ae81-90bc873ca54e', 'Event Planner', 'Corporate Event Planning', '8000', 'session', '3-person corporate event team for office parties, team outings, award nights and product demos. Basic package: venue shortlisting, vendor coordination, AV arrangements, catering plan and run-of-show. Full package: on-site management — registration desk, AV setup coordination, stage management, catering supervision and pack-down. Up to 100 guests. Hyderabad IT parks and coworking venues familiar. Book 7 days in advance.', 8, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:45:14.893664+00', null, '+91 98400 60009', 'vikram.corporate@focsera.com', 'Vikram Joshi & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:45:14.893664+00', null, 15, true), 
