('e5f92832-bc21-49e4-ae01-334f20fc724d', 'Design Expert', 'Logo & Brand Identity', '5000', 'session', 'Brand identity designer who delivers a complete logo system remotely. Session 1: discovery call — business story, target audience and visual direction. Delivers 3 concepts within 24 hrs. Session 2: chosen concept refined with full brand kit — logo variations, colour palette, typography and usage guidelines. Final files in AI, PNG and PDF. 2 revision rounds included. Delivered and handed over in 48 hrs.', 8, true, '5.0', 198, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70001', 'brand.kavya@focsera.com', 'Kavya Design & Team', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=200&h=200&auto=format&fit=crop', 17.4486, 78.3908, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('fdea4a6e-646a-4543-9ebb-a1640e77e2ba', 'Photographer', 'Maternity Shoot', '4500', 'session', '2-person maternity team — photographer and styling assistant. Arrives at your home with a compact kit: ring light, reflector, floral props and gowns in a carry bag. iPhone behind-the-scenes + mirrorless camera for hero shots. Edits on-site before leaving. 50 digital photos in 24 hrs. Framed wall print in 48 hrs.', 7, true, '5.0', 224, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11201', 'divyaa.maternity@focsera.com', 'Divyaa Rao & Team', 'https://images.unsplash.com/photo-1517841905240-472988babdf9?q=80&w=200&h=200&auto=format&fit=crop', 17.4486, 78.3908, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('aaa86b38-1fe4-4709-8049-f1d4ecc06d96', 'Photographer', 'Mehndi / Haldi Shoot', '4000', 'session', '2-person mehndi and haldi team. Compact portable flash and reflector in a shoulder bag. iPhone covers the energy and chaos, mirrorless captures close-up mehndi details and vibrant haldi colour. On-site editing. 80 digital photos in 24 hrs. Framed print in 48 hrs. Both ceremonies covered in one session.', 7, true, '5.0', 145, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11209', 'gautam.haldi@focsera.com', 'Gautam Shetty & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.4486, 78.3908, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('4ac7fa3c-26ef-4bc8-b000-cc84a35a66b0', 'Design Expert', 'Menu Design', '3500', 'session', 'Restaurant and cafe menu designer working remotely. Dine-in menus, QR code digital menus, takeaway menus and social media food cards all covered. Sends 2 design concepts within 24 hrs. Final files in print-ready PDF, editable Canva and web-optimised formats. Food photography placeholders or your own images used. 2 revision rounds included. Works for restaurants, cafes, cloud kitchens and home bakers.', 5, true, '4.8', 189, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70006', 'menu.chitra@focsera.com', 'Chitra Design & Team', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=200&h=200&auto=format&fit=crop', 17.38, 78.48, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('44e75086-f26f-48c5-aedf-aadf6a2a7eb6', 'Interior Designer', 'Modular Kitchen Design', '6000', 'session', 'Kitchen design specialist who visits your home and designs your complete modular kitchen. Session 1: measures kitchen, discusses requirements and creates 3D layout with material and colour options. Session 2: finalises design, prepares BOQ and coordinates with modular kitchen vendor. Countertop, shutter, hardware and appliance placement all planned. Works with all major Hyderabad modular kitchen brands.', 8, true, '4.9', 134, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80003', 'kitchen.sneha@focsera.com', 'Sneha Interiors & Team', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.44, 78.5, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('a8871de4-4005-4cbd-9c42-452ac1012492', 'Editor', 'Motion Graphics / Titles', '4500', 'session', 'Motion graphics designer who creates animated titles, lower thirds, logo reveals and infographic animations remotely. After Effects and Premiere Pro. Session covers up to 5 custom motion graphics elements. YouTube intros, podcast openers, corporate video title sequences and social media animations all covered. Delivered in 24 hrs as MOV with transparent background for easy drag and drop into any project.', 6, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70012', 'motion.kiran@focsera.com', 'Kiran Edit & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.42, 78.45, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('c602399a-1a87-4d6a-af80-8bf9a558e3d5', 'Reel Maker', 'Motivational / Quote Reels', '3000', 'session', 'Solo reel creator who comes to your home, office or terrace and shoots + edits 5 motivational or quote reels in one session. Minimal kit — iPhone Pro, ring light and a reflector. Shoots talking head, voiceover b-roll and aesthetic detail clips. Edits with animated text, kinetic typography and royalty-free music on-site. Delivered in 24 hrs. Perfect for coaches, speakers, educators and personal brands.', 4, true, '4.8', 98, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40010', 'priya.quotereels@focsera.com', 'Priya Menon & Team', 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?q=80&w=200&h=200&auto=format&fit=crop', 17.365, 78.495, false, '2026-03-21 17:37:40.713931+00', null, 20, true), 
('c15fc282-dae6-4a19-b73f-1fb43f11e734', 'Videographer', 'Music Video / Song Reel', '5500', 'session', '3-person music video team — director, videographer and editor. LED colour gels, iPhone on gimbal for movement shots and mirrorless for cinematic stills. Comes to your home, rooftop or chosen single location. Shoots and edits a 60–90 second music video or song reel on-site. Delivered in 24 hrs. Instagram Reels, YouTube Shorts and Spotify Canvas ready. Indie artists and creators.', 7, true, '5.0', 167, ARRAY[]::text[], '2026-03-21 17:24:58.380908+00', null, '+91 98400 20012', 'deepak.musicvid@focsera.com', 'Deepak Rao & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:24:58.380908+00', null, 15, true), 
