('89ea3513-9ccc-46a5-b7b3-7e36a99b38b5', 'Interior Designer', 'Office / Commercial Interior', '8000', 'session', 'Commercial interior design team of 2 for offices, clinics, salons, cafes and retail shops. Session 1: site visit, space planning and mood board. Session 2: complete design package — layout, furniture selection, lighting plan, colour palette and vendor list. Session 3: execution supervision. Hyderabad coworking spaces, IT offices and startup studios a speciality. 3D render provided before any work begins.', 9, true, '5.0', 156, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80011', 'office.aryan@focsera.com', 'Aryan Interiors & Team', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?q=80&w=200&h=200&auto=format&fit=crop', 17.399, 78.477, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('d407dffd-8b0c-4f5d-841a-bdd1ff09e533', 'Design Expert', 'Packaging Design', '5000', 'session', 'Product packaging designer working remotely for D2C brands, home businesses and physical product sellers. Boxes, pouches, labels, stickers, bottles and bags all covered. Session 1: brief + mood board. Delivers 2 packaging concepts in 24 hrs. Session 2: chosen concept refined with print-ready dieline files. Suitable for food, cosmetics, jewellery, apparel and gift packaging.', 6, true, '4.9', 143, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70005', 'pack.meera@focsera.com', 'Meera Design & Team', 'https://pub-962ecf16eb9a4629a9bf8d004682ebc5.r2.dev/PackageDesigning.png', 17.45, 78.49, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('a4ee3182-4bf5-48e9-a2e3-865cb6e11529', 'Interior Designer', 'Painting & Wall Finish', '5000', 'session', 'Interior painting and wall finish specialist who visits your home and handles the complete painting job. Texture painting, stencil patterns, ombre walls, metallic finishes and standard emulsion all covered. Session 1: colour selection and surface preparation. Session 2+: execution. Brings own materials and tools. Clean work, no mess left behind. Per room pricing available. Hyderabad-wide service.', 6, true, '4.8', 178, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80007', 'paint.nandini@focsera.com', 'Nandini Interiors & Team', 'https://images.unsplash.com/photo-1487412720507-e7ab37603c6f?q=80&w=200&h=200&auto=format&fit=crop', 17.385, 78.4867, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('1ae562aa-bc24-46c0-b4da-d7a887c67351', 'Photographer', 'Personal Branding / LinkedIn', '4500', 'session', 'Solo or 2-person personal branding team. iPhone for workspace lifestyle shots, mirrorless for headshots and portraits. Foldable backdrop and LED panel in a laptop bag. Covers headshots, desk setup and action frames. On-site editing. 50 digital photos in 24 hrs. LinkedIn-optimised crops included.', 9, true, '5.0', 156, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11211', 'sudhir.exec@focsera.com', 'Sudhir Bose & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.46, 78.36, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('af6d0f93-b67c-4d4d-8207-d69da0236331', 'Reel Maker', 'Personal Portfolio Reel', '3500', 'session', 'Solo reel maker who comes to your chosen location and creates a cinematic personal portfolio reel in one session. iPhone Pro on gimbal, mirrorless for hero frames, portable LED panel. Captures who you are — your work, personality, skills and story. Edits a 60–90 second portfolio reel on-site with music and text. Delivered in 24 hrs. Perfect for models, artists, freelancers, founders and job seekers.', 5, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40008', 'kiran.portfolioreel@focsera.com', 'Kiran Bose & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.42, 78.45, false, '2026-03-21 17:37:40.713931+00', null, 15, true), 
('6cd1618a-7413-4bd0-99cd-f6efb6242bef', 'Photographer', 'Pet Photography', '3500', 'session', '2-person pet team — photographer and animal handler. Compact kit: foldable backdrop, softbox, treats and toys in a backpack. iPhone for action moments, mirrorless for portraits. Comes to your home where pets are most relaxed. 50 digital photos in 24 hrs. Framed pet portrait in 48 hrs.', 6, true, '5.0', 89, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11217', 'nisha.pets@focsera.com', 'Nisha Verma & Team', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.435, 78.46, false, '2026-03-21 17:18:30.121689+00', null, 20, true), 
('e391d15b-eb12-46ae-84b6-6be9e35e9582', 'Editor', 'Photo Editing / Retouching', '2500', 'session', 'Photo editor who receives your images and returns professionally retouched photos remotely. Up to 50 photos per session. Skin retouching, background removal, colour correction, object removal and creative edits all covered. Send via Google Drive. Delivered in 24 hrs in full resolution JPG and web-optimised versions. Works for photographers, businesses, e-commerce sellers and individuals.', 6, true, '5.0', 312, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70008', 'photo.edit.priya@focsera.com', 'Priya Edit & Team', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&w=200&h=200&auto=format&fit=crop', 17.399, 78.477, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('2949cdaf-183a-4b96-8bee-2979a6c5e697', 'Design Expert', 'Pitch Deck / Presentation Design', '5500', 'session', 'Pitch deck designer who transforms your raw content into an investor-ready presentation remotely. Session 1: review your content and agree structure. Delivers designed deck within 24 hrs. Session 2: revisions and final polish. Up to 20 slides per session. PowerPoint, Google Slides and Canva formats available. Data visualisation, infographics and icon sets included. Used by Hyderabad startups for VC pitches.', 7, true, '5.0', 167, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70003', 'deck.sudhir@focsera.com', 'Sudhir Design & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.46, 78.36, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('9b20b33a-0003-411d-b9f8-dc6a28ad8a00', 'Reel Maker', 'Podcast / Interview Clips', '3500', 'session', '2-person podcast clip team — videographer and editor. Ring light, lav mic and mirrorless for clean talking head, iPhone for reaction and detail shots. Comes to your home, office or studio. Shoots a full interview or podcast session and cuts 5 short viral clips with animated captions, progress bars and audiogram visuals. Delivered in 24 hrs. LinkedIn, Instagram Reels and YouTube Shorts ready.', 5, true, '4.9', 134, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40007', 'vikram.podclips@focsera.com', 'Vikram Joshi & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:37:40.713931+00', null, 15, true), 
('aa3c4392-7065-4e93-a673-9f12ea294dea', 'Editor', 'Podcast Editing', '3000', 'session', 'Podcast editor who receives your raw audio or video recording and delivers a clean, professional episode remotely. Removes filler words, background noise, long pauses and mistakes. Adds intro, outro, chapter markers and show notes. Up to 60 minutes of raw audio per session. Delivered in 24 hrs in MP3 and WAV. YouTube audiogram version included. Works for solo podcasters, interview shows and business podcasts.', 5, true, '4.9', 156, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70009', 'pod.edit.vikram@focsera.com', 'Vikram Edit & Team', 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('5d4e5b47-58b0-4422-93b6-e7603eb595f5', 'Design Expert', 'Poster / Flyer Design', '2500', 'session', 'Fast turnaround poster and flyer designer working remotely. Event posters, sale flyers, festival offers, job openings, restaurant specials — any occasion. Sends 2 design concepts within 12 hrs. Final print and digital ready files in A4, A3 and social media sizes. 2 revision rounds included. Works for individuals, businesses and event teams across Hyderabad.', 4, true, '4.9', 312, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70004', 'poster.arjun@focsera.com', 'Arjun Design & Team', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('ddd85fbe-292e-4bb1-ab73-f4134bb802a1', 'Reel Maker', 'Product / Brand Reel', '4000', 'session', '2-person product reel team arriving at your shop, home or warehouse. White sweep, LED panel and macro lens in one bag. iPhone for lifestyle and unboxing angles, mirrorless for clean hero product shots. Shoots and edits 3 short product reels — 15 sec, 30 sec and 60 sec versions. Trending audio and text overlays added. Delivered in 24 hrs. Instagram ad, WhatsApp catalogue and website ready.', 6, true, '5.0', 198, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40003', 'sanjay.productreels@focsera.com', 'Sanjay Kulkarni & Team', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=200&h=200&auto=format&fit=crop', 17.37, 78.43, false, '2026-03-21 17:37:40.713931+00', null, 20, true), 
('90616537-69b2-41bd-800a-e1350ca70ac3', 'Event Host', 'Product Launch Host', '9000', 'session', 'Product launch host with experience in startup unveilings, app launches, brand events and retail openings in Hyderabad. Builds excitement, introduces founders, demos the product on stage and manages media and guest interactions. Brings energy, clarity and a sharp script. Fluent in English, Hindi and Telugu. Up to 3 hours. Works with your PR or marketing team for seamless execution. Book 7 days in advance.', 7, true, '4.9', 112, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 90006', 'launch.arjun@focsera.com', 'Arjun Nair', 'https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.3489, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
