('d24b4521-24fb-4b82-b9fe-be6309a7d06a', 'Interior Designer', 'Rental / Budget Makeover', '4500', 'session', 'Budget interior specialist for rented flats and PGs. No drilling, no permanent changes. Transforms your space with furniture arrangement, removable wallpaper, LED strip lights, curtains, rugs and affordable décor. Comes to your home with a curated shopping cart. Session includes setup and styling. Perfect for IT professionals, students and new renters in Hyderabad. Complete makeover in 1 day.', 5, true, '4.9', 312, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80006', 'rental.chitra@focsera.com', 'Chitra Interiors & Team', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&w=200&h=200&auto=format&fit=crop', 17.405, 78.51, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('bd69fe4f-6b4b-49b4-afd5-6be0754dd336', 'Reel Maker', 'Restaurant / Food Reel', '4000', 'session', '2-person food reel team — videographer and food stylist. Compact LED panel, iPhone Pro on gimbal and mirrorless with macro lens. Comes to your restaurant, cafe or cloud kitchen. Shoots sizzle close-ups, chef in action, plating moments and ambience. Edits 3 food reels on-site. Trending audio and text added. Delivered in 24 hrs. Zomato, Swiggy, Instagram and Google Maps ready.', 6, true, '5.0', 176, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40004', 'nidhi.foodreels@focsera.com', 'Nidhi Sharma & Team', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=200&h=200&auto=format&fit=crop', 17.38, 78.48, false, '2026-03-21 17:37:40.713931+00', null, 20, true), 
