('a4fdf581-51dd-4587-87fd-4e7730b47ca1', 'Photographer', 'Saree Shoot', '3500', 'session', '2-person saree team — photographer and styling assistant who helps with draping, pleats and accessories at your home. Reflector and a small ring light, iPhone for BTS, mirrorless for hero frames. Every silk and weave shot at its best. 50 digital photos in 24 hrs. Framed saree portrait in 48 hrs.', 7, true, '4.9', 189, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11208', 'anupama.saree@focsera.com', 'Anupama Varma & Team', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=200&h=200&auto=format&fit=crop', 17.42, 78.45, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('9fb7f9cc-28e3-4d5b-ac74-fbd40c3ed823', 'Design Expert', 'Social Media Graphics / Templates', '4000', 'session', 'Social media designer who creates a complete set of branded templates remotely. Covers Instagram posts, stories, reels covers, YouTube thumbnails and WhatsApp status. 10 editable Canva or Figma templates delivered per session. Matches your brand colours and fonts. Content calendar suggestions included. First batch delivered in 24 hrs. Works for creators, businesses and personal brands.', 5, true, '4.9', 234, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70002', 'social.isha@focsera.com', 'Isha Design & Team', 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?q=80&w=200&h=200&auto=format&fit=crop', 17.435, 78.46, false, '2026-03-21 17:51:07.355983+00', null, 20, true), 
('f4e1f6c3-316b-41a8-ac36-2fab58fa3bc5', 'Vibe Coder', 'Social Media Tech Setup', '3500', 'session', 'Solo tech setup specialist who configures your complete social media tech stack in one session. Doorstep or remote. Link-in-bio page (Linktree alternative), Meta Pixel installation, Google Analytics setup, scheduling tool configuration (Buffer / Hootsuite), Instagram and Facebook shop setup. Everything connected and tested. Training walkthrough given on-site. Delivered in 24 hrs.', 4, true, '4.8', 112, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30009', 'social.chitra@focsera.com', 'Chitra Dev & Team', 'https://images.unsplash.com/photo-1531746020798-e6953c6e8e04?q=80&w=200&h=200&auto=format&fit=crop', 17.38, 78.48, false, '2026-03-21 17:30:26.695346+00', null, 25, true), 
('a5bb5ffe-9f3e-47a8-b1af-a2fab7c70f69', 'Interior Designer', 'Space Planning + 3D Visualisation', '7000', 'session', 'Space planning and 3D visualisation specialist who visits your home or under-construction flat and creates a complete 3D design. Session 1: measurements and brief. Session 2: delivers photorealistic 3D renders of every room — furniture layout, materials and lighting visualised before you spend a rupee. SketchUp and Lumion renders. 3 revision rounds included. Perfect for new flats and full home renovations.', 9, true, '5.0', 167, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80005', '3d.vikram@focsera.com', 'Vikram Interiors & Team', 'https://images.unsplash.com/photo-1539571696357-5a69c17a67c6?q=80&w=200&h=200&auto=format&fit=crop', 17.43, 78.38, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('a9be2b80-acf1-4989-8c32-17d3173431a7', 'Event Planner', 'Surprise Party Planning', '5000', 'session', '2-person surprise party team who secretly coordinate with you to plan and set up a surprise at your home, terrace or a nearby venue. Basic package: planning + secret vendor coordination. Full package: arrives while the guest of honour is away, sets up complete décor, hides everything before they arrive and cues the surprise moment. Balloon drop, custom backdrop and cake coordination included.', 5, true, '4.9', 134, ARRAY[]::text[], '2026-03-21 17:45:14.893664+00', null, '+91 98400 60003', 'rohit.surprise@focsera.com', 'Rohit Varma & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.415, 78.435, false, '2026-03-21 17:45:14.893664+00', null, 20, true), 
('24ff6ff4-065d-4ca0-b06f-2ce3c79131fd', 'Vibe Coder', 'UI/UX Design + Prototype', '5000', 'session', 'Solo Figma designer who creates wireframes and high-fidelity prototypes in a single working session. Comes to your office or joins remotely. Mobile app screens, website layouts or dashboard designs. Clickable prototype handed over at end of session. 10–15 screens covered per session. Developer handoff file included. Delivered in 24 hrs.', 7, true, '5.0', 198, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30003', 'design.kavya@focsera.com', 'Kavya Design & Team', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=200&h=200&auto=format&fit=crop', 17.4486, 78.3908, false, '2026-03-21 17:30:26.695346+00', null, 15, true), 
('f76e4eb4-f73d-46e8-b3c9-2c9c5f659b25', 'Editor', 'Video Editing / Reels & YouTube', '3500', 'session', 'Video editor who receives your raw footage and delivers polished edited videos remotely. Reels, YouTube videos, product videos and brand content all covered. Send your footage via Google Drive or WeTransfer. Session covers up to 10 minutes of raw footage. Colour correction, audio cleanup, transitions, captions and music added. Delivered in 24 hrs. Instagram Reels, YouTube and WhatsApp ready.', 5, true, '4.9', 267, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70007', 'edit.deepak@focsera.com', 'Deepak Edit & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('1e3b3d85-6aac-448b-8c32-82ceec8a1d3f', 'Photographer', 'Vintage / Retro Shoot', '4000', 'session', '2-person retro team arriving with a vintage prop bag — typewriter, rotary phone, cassette tapes, old suitcase and period wardrobe tips. iPhone for film-grain candids, mirrorless for hero frames. On-site editing with authentic retro grade. 50 digital photos + Polaroid-style prints in 24 hrs.', 7, true, '5.0', 198, ARRAY[]::text[], '2026-03-21 17:18:30.121689+00', null, '+91 98400 11215', 'kiran.vintage@focsera.com', 'Kiran Bose & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.42, 78.45, false, '2026-03-21 17:18:30.121689+00', null, 15, true), 
('539066fa-9b13-409b-bf20-5517cbcb411c', 'Interior Designer', 'Wardrobe & Storage Design', '5500', 'session', 'Wardrobe and storage design specialist who visits your home and designs your complete modular wardrobe or storage solution. Measures the space, understands your storage needs and creates a layout — shelves, drawers, hanging sections and shoe racks. Co-ordinates with carpenter or modular wardrobe vendor. Walk-in wardrobe, sliding door and swing door designs all covered. 3D layout provided before execution.', 7, true, '4.9', 145, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 80008', 'wardrobe.lalitha@focsera.com', 'Lalitha Interiors & Team', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.46, 78.36, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('735c2ca5-870f-4ca7-8f23-6d2d6136de54', 'Developer', 'Web App Development', '5500', 'session', '2-person web app team — frontend and backend developer. Builds full-stack web applications doorstep or remotely. React, Next.js, Node.js, PostgreSQL stack. Session 1: scoping and architecture. Session 2–3: core features — auth, dashboard, data management. Final session: deployment, testing and handover. Suitable for admin panels, SaaS tools, booking systems and internal business apps. Book multiple sessions to complete your build.', 8, true, '4.9', 167, ARRAY[]::text[], '2026-03-21 17:41:16.254993+00', null, '+91 98400 50002', 'webapp.sudhir@focsera.com', 'Sudhir Dev & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.46, 78.36, false, '2026-03-21 17:41:16.254993+00', null, 15, true), 
('dfe5373a-b502-4e4e-b037-46bf08fda1a8', 'Vibe Coder', 'Website Development', '5000', 'session', '2-person web dev team — frontend developer and designer. Builds a complete business website in a focused session at your office or remotely. React, Next.js or WordPress. Up to 5 pages: Home, About, Services, Gallery, Contact. Mobile responsive, fast loading and SEO-ready. Domain connected and live by end of session. Full access handed over in 24 hrs.', 8, true, '4.9', 221, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30005', 'web.sudhir@focsera.com', 'Sudhir Dev & Team', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=200&h=200&auto=format&fit=crop', 17.46, 78.36, false, '2026-03-21 17:30:26.695346+00', null, 15, true), 
('f83773a2-f3ac-424c-9210-7652fdf06118', 'Reel Maker', 'Wedding / Event Highlight Reel', '5500', 'session', '3-person event reel team — 2 shooters and 1 on-site editor. iPhone Pro on gimbal for candid flow, mirrorless for cinematic moments, portable LED for indoor coverage. Covers key moments — entry, ceremony, celebrations and candid emotions. Editor cuts a 2–3 minute highlight reel on-site while the event continues. Trending audio, titles and colour grade applied. Delivered in 24 hrs. Shared directly to WhatsApp.', 7, true, '5.0', 189, ARRAY[]::text[], '2026-03-21 17:37:40.713931+00', null, '+91 98400 40009', 'deepak.eventreel@focsera.com', 'Deepak Rao & Team', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:37:40.713931+00', null, 15, true), 
('354ee033-9708-4de9-9717-1095ce7b18b6', 'Editor', 'Wedding / Event Video Edit', '6000', 'session', 'Wedding and event video editor who receives your raw footage and delivers a cinematic highlight film remotely. Send footage via Google Drive. Session covers up to 4 hours of raw footage. Delivers a 3–5 minute highlight reel with colour grade, music sync, titles and transitions. Full ceremony edit available as add-on. Delivered in 48 hrs. Trusted by Hyderabad wedding photographers and videographers.', 8, true, '5.0', 198, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 70010', 'wed.edit.nalini@focsera.com', 'Nalini Edit & Team', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200&h=200&auto=format&fit=crop', 17.415, 78.435, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('f4e5a53d-dc2b-4ba8-8b4b-3e1eb3d3e088', 'Event Host', 'Wedding / Sangeet MC', '10000', 'session', 'Experienced wedding and sangeet MC who brings the celebration to life at your venue. Covers sangeet night, reception and family events. Curates playlist with your family, anchors dance performances, introduces speakers and keeps guests entertained between programme items. Telugu, Hindi and English. Brings own wireless mic. Up to 5 hours. 100+ weddings hosted across Hyderabad. Book 7 days in advance.', 9, true, '5.0', 212, ARRAY[]::text[], '2026-03-21 17:51:07.355983+00', null, '+91 98400 90004', 'mc.deepak@focsera.com', 'Deepak Rao', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=200&h=200&auto=format&fit=crop', 17.41, 78.52, false, '2026-03-21 17:51:07.355983+00', null, 15, true), 
('da369a26-fbdb-405b-9806-7d1301562a18', 'Vibe Coder', 'WhatsApp Business Automation', '5000', 'session', 'Solo automation dev who sets up your complete WhatsApp Business system in one session at your office or remotely. Auto-replies, broadcast lists, catalogue setup, quick replies and away messages. Integrates with your CRM or Google Sheets if needed. WhatsApp API or Business App — both covered. Live and tested by end of session. Training walkthrough included. Handed over in 24 hrs.', 5, true, '4.9', 156, ARRAY[]::text[], '2026-03-21 17:30:26.695346+00', null, '+91 98400 30008', 'wa.farhan@focsera.com', 'Farhan Dev & Team', 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?q=80&w=200&h=200&auto=format&fit=crop', 17.385, 78.46, false, '2026-03-21 17:30:26.695346+00', null, 20, true);
